def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = 2000 + (ratio - 2) * 200
        elif ratio > 1:
            priorities[i] = 500 + (ratio - 1) * 300
        elif ratio == 1:
            priorities[i] = 300
        else:
            dif = capacity - item
            score = 0
            for power in range(1, 8):
                term = (dif / capacity) ** power
                if term < 0.05:
                    score += term * 80 / power
                elif term < 0.3:
                    score += term * 25 / (power * 2)
                else:
                    score += term * 10 / (power ** 2)
            avg = np.mean(bins)
            variance = np.var(bins)
            if capacity > avg and dif > avg * 0.5:
                score *= 0.8
            if variance > 0.5 * avg:
                score += 0.2
            if score < 0.2:
                priorities[i] = score * 5
            else:
                priorities[i] = 1 / (score + 0.5)
        if i % 2 == 0:
            priorities[i] *= 0.9
        else:
            priorities[i] *= 1.1
    min_priority = np.min(priorities[np.isfinite(priorities)])
    for i in range(n):
        if np.isfinite(priorities[i]) and priorities[i] == min_priority:
            priorities[i] *= 0.5
    return priorities
